import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Scanner;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        String directoryPath = "/path/to/directory/";
        Path filePath = Paths.get(directoryPath, fileName).normalize();

        if (filePath.startsWith(Paths.get(directoryPath)) && Files.exists(filePath) && !Files.isDirectory(filePath)) {
            System.out.println("File exists.");
            // Further processing of the file can be done securely here
        } else {
            System.out.println("File not found.");
        }
    }
}

